mapper.select:
    SELECT vhi.*, hrMap.*
     FROM esg.tb_worker_health_guide_hr hrMap
LEFT JOIN esg.v_hr_info vhi
       ON hrMap.hr_id = vhi.hr_id
    WHERE 1 = 1
      AND hrMap.write_year = #{writeYear}
      AND hrMap.doc_no = #{docNo}
      AND hrMap.doc_type = #{docType}
      AND hrMap.comp_id = #{compId}

        AND hrMap.gubun = #{searchText}

mapper.delete:
DELETE FROM esg.tb_worker_health_guide_hr
 WHERE 1 = 1
   AND write_year = #{writeYear}
   AND doc_no = #{docNo}
   AND doc_type = #{docType}
   AND comp_id = #{compId}
   AND doc_seq = #{docSeq}

mapper.update:
UPDATE esg.tb_worker_health_guide
SET
    orgn_nm = #{orgnNm},
    sex = #{sex},
    age = #{age},
    service_years = #{serviceYears},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

UPDATE esg.tb_worker_health_guide_counsel
SET
    health_opinion = #{healthOpinion},
    aftercare_opinion = #{aftercareOpinion},
    work_aptitude_yn = #{workAptitudeYn},
    corrective_action = #{correctiveAction},
    use_yn = #{counselUseYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE 1 = 1
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

